  7 | // Simple in-memory implementation with optional SQLite fallback
  8 | class VectorMemory {
  9 |   constructor(options = {}) {
 10 |     this.storePath = options.storePath || './data/memory.db';
 11 |     this.embeddingsUrl = options.embeddingsUrl || 'http://localhost:3847';
 12 |     this.collection = options.collection || 'default';
 13 |     this.memories = new Map();
 14 |     this.initialized = false;
 15 |     this.db = null;
 16 |   }
