 18 |   async initialize() {
 19 |     if (this.initialized) return;
 20 | 
 21 |     console.log('[VectorMemory] Initializing...');
 22 | 
 23 |     // Try to load better-sqlite3 for persistent storage
 24 |     try {
 25 |       const Database = require('better-sqlite3');
 26 |       const dbDir = path.dirname(this.storePath);
 27 |       if (!fs.existsSync(dbDir)) {
 28 |         fs.mkdirSync(dbDir, { recursive: true });
 29 |       }
 30 |       this.db = new Database(this.storePath);
 31 |       
 32 |       this.db.exec(`
 33 |         CREATE TABLE IF NOT EXISTS memories (
 34 |           id TEXT PRIMARY KEY,
 35 |           content TEXT NOT NULL,
 36 |           embedding TEXT NOT NULL,
 37 |           collection TEXT NOT NULL DEFAULT 'default',
 38 |           metadata TEXT DEFAULT '{}',
 39 |           created_at TEXT NOT NULL,
 40 |           updated_at TEXT NOT NULL,
 41 |           INDEX idx_collection (collection),
 42 |           INDEX idx_created (created_at)
 43 |         );
 44 |       `);
 45 |       
 46 |       console.log('[VectorMemory] SQLite storage initialized');
 47 |     } catch (e) {
 48 |       console.log('[VectorMemory] Running in-memory only mode');
 49 |       this.db = null;
 50 |     }
 51 | 
 52 |     // Load existing memories into memory
 53 |     if (this.db) {
 54 |       try {
 55 |         const rows = this.db.prepare('SELECT * FROM memories').all();
 56 |         for (const row of rows) {
 57 |           this.memories.set(row.id, {
 58 |             id: row.id,
 59 |             content: row.content,
 60 |             embedding: JSON.parse(row.embedding),
 61 |             collection: row.collection,
 62 |             metadata: JSON.parse(row.metadata),
 63 |             createdAt: row.created_at,
 64 |             updatedAt: row.updated_at
 65 |           });
 66 |         }
 67 |         console.log(`[VectorMemory] Loaded ${this.memories.size} memories`);
 68 |       } catch (e) {
 69 |         console.error('[VectorMemory] Failed to load memories:', e.message);
 70 |       }
 71 |     }
 72 | 
 73 |     this.initialized = true;
 74 |     console.log('[VectorMemory] Initialization complete');
 75 |   }
 76 | 
 77 |   generateId() {
 78 |     return `mem_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
 79 |   }
 80 | 
 81 |   async embed(text) {
 82 |     // Try local embeddings endpoint first
 83 |     try {
 84 |       const response = await fetch(`${this.embeddingsUrl}/api/embed`, {
 85 |         method: 'POST',
 86 |         headers: { 'Content-Type': 'application/json' },
 87 |         body: JSON.stringify({ text, model: 'nomic-embed-text' }),
 88 |         signal: AbortSignal.timeout(30000)
 89 |       });
 90 |       
 91 |       if (response.ok) {
 92 |         const data = await response.json();
 93 |         return { embedding: data.embedding || data.vector || [], provider: 'local' };
 94 |       }
 95 |     } catch (e) {
 96 |       console.log('[VectorMemory] Local embeddings failed, trying Ollama');
 97 |     }
 98 | 
 99 |     // Try Ollama
100 |     try {
101 |       const response = await fetch('http://localhost:11434/api/embeddings', {
102 |         method: 'POST',
103 |         headers: { 'Content-Type': 'application/json' },
104 |         body: JSON.stringify({ prompt: text, model: 'nomic-embed-text' })
105 |       });
106 |       
107 |       if (response.ok) {
108 |         const data = await response.json();
109 |         return { embedding: data.embedding, provider: 'ollama' };
110 |       }
111 |     } catch (e) {
112 |       console.log('[VectorMemory] Ollama embeddings failed');
113 |     }
114 | 
115 |     // Generate simple hash-based embedding as fallback
116 |     return { embedding: this.simpleEmbedding(text), provider: 'fallback' };
117 |   }
118 | 
119 |   // Simple hash-based embedding for fallback
120 |   simpleEmbedding(text) {
121 |     const dim = 384;
122 |     const embedding = new Array(dim).fill(0);
123 |     for (let i = 0; i < text.length; i++) {
124 |       embedding[i % dim] += text.charCodeAt(i);
125 |     }
126 |     // Normalize
127 |     const norm = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
128 |     return embedding.map(v => v / (norm || 1));
129 |   }
130 | 
131 |   cosineSimilarity(a, b) {
132 |     if (a.length !== b.length) return 0;
133 |     let dotProduct = 0, normA = 0, normB = 0;
134 |     for (let i = 0; i < a.length; i++) {
135 |       dotProduct += a[i] * b[i];
136 |       normA += a[i] * a[i];
137 |       normB += b[i] * b[i];
138 |     }
139 |     if (normA === 0 || normB === 0) return 0;
140 |     return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
141 |   }
