176 |           VALUES (?, ?, ?, ?, ?, ?, ?)
177 |         `).run(id, content, JSON.stringify(embedding), collection, JSON.stringify(options.metadata || {}), now, now);
178 |       } catch (e) {
179 |         console.error('[VectorMemory] Failed to store memory:', e.message);
180 |       }
181 |     }
182 | 
183 |     console.log(`[VectorMemory] Added memory: ${id} to "${collection}"`);
184 |     return entry;
185 |   }
