468 |   /**
469 |    * Determine task complexity based on input length and history
470 |    * @param {string} message - The user message
471 |    * @param {Array} history - Message history
472 |    * @returns {string} - 'simple' or 'complex'
473 |    */
474 |   _determineTaskComplexity(message, history) {
475 |     // Simple heuristic: complex tasks have long inputs or many history messages
476 |     const messageLength = message?.length || 0;
477 |     const historyLength = history?.length || 0;
478 |     const totalContentLength = messageLength + (history?.reduce((sum, msg) => sum + (msg.content?.length || 0), 0) || 0);
479 |     
480 |     // Consider complex if:
481 |     // - Message is very long (> 1000 chars)
482 |     // - History has many messages (> 10)
483 |     // - Total content is large (> 5000 chars)
484 |     if (messageLength > 1000 || historyLength > 10 || totalContentLength > 5000) {
485 |       return 'complex';
486 |     }
487 |     return 'simple';
488 |   }
